   182	async fn claim_next_ready_job<C>(
   183	    conn: &C,
   184	    worker_id: &str,
   185	    lease_seconds: i64,
   186	) -> Result<Option<ClaimedOutboxJob>, ApiError>
   187	where
   188	    C: ConnectionTrait + TransactionTrait,
   189	{
   190	    let tx = conn.begin().await.map_err(ApiError::internal)?;
   191	    acquire_metadata_write_lock(&tx).await?;
   192	    let now = now_i64()?;
   193	    let runnable = Condition::any()
   194	        .add(
   195	            Condition::all()
   196	                .add(entities::outbox_job::Column::State.eq(JOB_READY))
   197	                .add(entities::outbox_job::Column::NextRunAtUnix.lte(now)),
   198	        )
   199	        .add(
   200	            Condition::all()
   201	                .add(entities::outbox_job::Column::State.eq(JOB_RUNNING))
   202	                .add(entities::outbox_job::Column::LeaseExpiresAtUnix.lte(now)),
   203	        );
   204	
   205	    let Some(job) = entities::outbox_job::Entity::find()
   206	        .filter(entities::outbox_job::Column::CompletedAtUnix.is_null())
   207	        .filter(runnable)
   208	        .order_by_asc(entities::outbox_job::Column::NextRunAtUnix)
   209	        .order_by_asc(entities::outbox_job::Column::CreatedAtUnix)
   210	        .order_by_asc(entities::outbox_job::Column::Id)
   211	        .one(&tx)
   212	        .await
   213	        .map_err(ApiError::internal)?
   214	    else {
   215	        tx.commit().await.map_err(ApiError::internal)?;
   216	        return Ok(None);
   217	    };
   218	
   219	    entities::outbox_job::Entity::update_many()
   220	        .filter(entities::outbox_job::Column::Id.eq(job.id.clone()))
   221	        .filter(entities::outbox_job::Column::CompletedAtUnix.is_null())
   222	        .col_expr(
   223	            entities::outbox_job::Column::State,
   224	            Expr::value(JOB_RUNNING),
   225	        )
   226	        .col_expr(
   227	            entities::outbox_job::Column::LeaseOwner,
   228	            Expr::value(Some(worker_id.to_string())),
   229	        )
   230	        .col_expr(
   231	            entities::outbox_job::Column::LeaseExpiresAtUnix,
   232	            Expr::value(Some(now.saturating_add(lease_seconds))),
   233	        )
   234	        .col_expr(
   235	            entities::outbox_job::Column::UpdatedAtUnix,
   236	            Expr::value(now),
   237	        )
   238	        .exec(&tx)
   239	        .await
   240	        .map_err(ApiError::internal)?;
   241	    tx.commit().await.map_err(ApiError::internal)?;
   242	
   243	    Ok(Some(ClaimedOutboxJob {
   244	        id: job.id,
   245	        kind: job.kind,
   246	        repo_id: job.repo_id,
   247	        repo_version: job.repo_version,
   248	        attempts: job.attempts,
   249	    }))
   250	}
