   252	async fn execute_outbox_job<C>(conn: &C, job: &ClaimedOutboxJob) -> Result<(), ApiError>
   253	where
   254	    C: ConnectionTrait + TransactionTrait,
   255	{
   256	    match job.kind.as_str() {
   257	        PROJECTION_READ_MODEL_REBUILD => {
   258	            rebuild_live_projection_read_models_for_job(conn, job).await
