   266	async fn rebuild_live_projection_read_models_for_job<C>(
   267	    conn: &C,
   268	    job: &ClaimedOutboxJob,
   269	) -> Result<(), ApiError>
   270	where
   271	    C: ConnectionTrait + TransactionTrait,
   272	{
   273	    let tx = conn.begin().await.map_err(ApiError::internal)?;
   274	    acquire_metadata_write_lock(&tx).await?;
   275	    let Some(repo) = entities::repository::Entity::find_by_id(job.repo_id.clone())
   276	        .one(&tx)
   277	        .await
   278	        .map_err(ApiError::internal)?
   279	    else {
   280	        tx.commit().await.map_err(ApiError::internal)?;
   281	        return Ok(());
   282	    };
   283	    if repo.change_version != job.repo_version {
   284	        tx.commit().await.map_err(ApiError::internal)?;
   285	        return Ok(());
   286	    }
   287	    let repo = repository_from_model(&tx, repo).await?;
   288	    save_live_projection_read_models(&tx, &repo).await?;
   289	    tx.commit().await.map_err(ApiError::internal)?;
   290	    Ok(())
   291	}
